type
  fprun* = proc (pParams: PARAMS): VOID {.stdcall.}

proc SleepyCrypt*(sleepTime: int): cint =
  
  var dwSleepTime: DWORD = cast[DWORD](sleepTime)
  ##  Create struct argument for the run function shellcode.
  var pParams: PARAMS
  ##  Set the base address of the current image.
  pParams.pBaseAddress = cast[LPVOID](GetModuleHandleA(nil))
  ##  Set the sleep time.
  pParams.dwSleepTime = dwSleepTime
  ##  Create RWX space. IOC.
  var pBuffer: LPVOID = VirtualAlloc(nil, cast[SIZE_T](shellcode_bin.len),
                                 MEM_COMMIT or MEM_RESERVE, PAGE_EXECUTE_READWRITE)
  if nil == pBuffer:
    echo("[!] VirtualAlloc failed\n")
    quit(1)
  copyMem(pBuffer, unsafeAddr shellcode_bin, cast[SIZE_T](shellcode_bin.len))
  ##  Make a function pointer to the run function shellcode.
  var Run: fprun = cast[fprun](pBuffer)
  ##  Call the run function shellcode after pressing a key.
  echo("[+] Press a key to sleep for : \n", pParams.dwSleepTime)
  Run(pParams)
  ##  Done!
  echo("[+] Awake again!")
  return 0

proc SleepyCryptLoop * (sleepTime: int): void =
  while(1 == 1):
    discard SleepyCrypt(sleepTime)
    Sleep(4000)

SleepyCryptLoop(10000)

